const profile = $input.first()?.json?.[0] || {};
const config = $('1. Set Master Credentials').first()?.json || {};
const rawTopic = profile.industry || profile.business_name || 'Business';
const cleanTopic = String(rawTopic).replace(/[^a-zA-Z0-9 ]/g, '').trim() || 'Business';
return [{ json: { ...config, businessName: profile.business_name || 'My Business', industry: profile.industry || 'General Industry', autoQuery: cleanTopic } }];

const xml = $input.first()?.json?.data || '';
const config = $('Auto-Extract Industry Topic').first()?.json || {};
const text = (v = '') => String(v).replace(/<!\[CDATA\[([\s\S]*?)\]\]>/g, '$1').replace(/<[^>]*>/g, '').trim();
const pick = (block, tag) => text((block.match(new RegExp(`<${tag}[^>]*>([\s\S]*?)<\/${tag}>`, 'i')) || [])[1] || '');
const matches = [...xml.matchAll(/<item>([\s\S]*?)<\/item>/gi)].slice(0, 5);
const items = matches.map((m) => {
  const item = m[1]; const title = pick(item, 'title'); const pub = pick(item, 'pubDate'); const traffic = pick(item, 'ht:approx_traffic');
  if (!title) return null;
  return {
    json: {
      workspaceId: config.workspaceId,
      title: `Google Trends: ${title}`,
      sourceUrl: `https://trends.google.com/trends/explore?q=${encodeURIComponent(title)}`,
      publishedAt: pub ? new Date(pub).toISOString() : new Date().toISOString(),
      sourceName: 'Google Trends RSS',
      sourceType: 'trend',
      content: `Outside viral market trend: ${title}. Approximate search traffic: ${traffic || 'Not specified'}. Public signal.`,
      automationSecret: config.automationSecret
    }
  };
}).filter(Boolean);
return items.length ? items : [];

const config = $('Auto-Extract Industry Topic').first()?.json || {};
const rawItems = $input.first()?.json?.items || [];
const items = rawItems.map((item) => {
  const s = item.snippet || {};
  const vId = item.id?.videoId || '';
  const title = s.title || '';
  if (!title || !vId) return null;
  return {
    json: {
      workspaceId: config.workspaceId,
      title: `YouTube Video: ${title}`,
      sourceUrl: `https://www.youtube.com/watch?v=${vId}`,
      publishedAt: s.publishedAt || new Date().toISOString(),
      sourceName: 'YouTube Data API',
      sourceType: 'report',
      content: `YouTube video content for industry '${config.industry}'. Title: ${title}. Channel: ${s.channelTitle || 'Unknown'}. Description: ${s.description || 'N/A'}`,
      automationSecret: config.automationSecret
    }
  };
}).filter(Boolean);
return items.length ? items : [];

const xml = $input.first()?.json?.data || '';
const config = $('Auto-Extract Industry Topic').first()?.json || {};
const text = (v = '') => String(v).replace(/<!\[CDATA\[([\s\S]*?)\]\]>/g, '$1').replace(/<[^>]*>/g, '').trim();
const pick = (block, tag) => text((block.match(new RegExp(`<${tag}[^>]*>([\s\S]*?)<\/${tag}>`, 'i')) || [])[1] || '');
const matches = [...xml.matchAll(/<item>([\s\S]*?)<\/item>/gi)].slice(0, 5);
const items = matches.map((m) => {
  const item = m[1]; const title = pick(item, 'title'); const link = pick(item, 'link'); const pub = pick(item, 'pubDate'); const source = pick(item, 'source');
  if (!title || !link) return null;
  return {
    json: {
      workspaceId: config.workspaceId,
      title: `Industry News: ${title}`,
      sourceUrl: link,
      publishedAt: pub ? new Date(pub).toISOString() : new Date().toISOString(),
      sourceName: source || 'Google News',
      sourceType: 'report',
      content: `Breaking industry news for '${config.businessName}' (${config.industry}). Headline: ${title}. Media outlet: ${source || 'Google News'}. Article link: ${link}`,
      automationSecret: config.automationSecret
    }
  };
}).filter(Boolean);
return items.length ? items : [];

const config = $('Auto-Extract Industry Topic').first()?.json || {};
const rawItems = $input.first()?.json?.items || [];
if (!rawItems.length) return [];
const views = rawItems.map((i) => Number(i.views || 0));
const avg = views.reduce((a, b) => a + b, 0) / views.length;
return [{
  json: {
    workspaceId: config.workspaceId,
    title: `Wikimedia Attention: ${config.industry}`,
    sourceUrl: `https://en.wikipedia.org/wiki/${encodeURIComponent(config.autoQuery.replace(/ /g, '_'))}`,
    publishedAt: new Date().toISOString(),
    sourceName: 'Wikimedia Pageviews API',
    sourceType: 'report',
    content: `Wikimedia pageview attention signal for industry '${config.industry}'. 30-day average daily pageviews: ${avg.toFixed(0)}.`,
    automationSecret: config.automationSecret
  }
}];
